const data = $json[0];
const ct = data.contactos || {};
const vd = data.vendedores || {};
const ia = data.detalles_ia || {};
const fecha = new Date().toLocaleDateString('es-HN', { year:'numeric', month:'long', day:'numeric' });
const folio = 'LRC-' + Date.now().toString().slice(-6);

const producto = ia.producto || ct.interes_principal || 'Producto';
const pago = ia.pago || ct.tipo_pago_preferido || 'A convenir';

const htmlContent = `<!DOCTYPE html>
<html lang='es'>
<head>
<meta charset='UTF-8'/>
<style>
  body { font-family: Arial, sans-serif; color: #111; max-width: 680px; margin: 0 auto; padding: 40px; }
  .header { text-align: center; border-bottom: 3px solid #E8195A; padding-bottom: 20px; margin-bottom: 30px; }
  .logo-name { font-size: 28px; font-weight: 900; color: #1B2F8A; }
  .logo-name span { color: #E8195A; }
  .folio { font-size: 12px; color: #666; margin-top: 6px; }
  .title { font-size: 16px; font-weight: 700; text-align: center; margin: 20px 0; text-transform: uppercase; letter-spacing: 2px; }
  .row { display: flex; justify-content: space-between; padding: 10px 0; border-bottom: 1px solid #eee; }
  .label { font-weight: 700; color: #444; font-size: 13px; }
  .value { color: #111; font-size: 13px; }
  .footer { margin-top: 40px; text-align: center; font-size: 11px; color: #888; }
  .seal { margin-top: 30px; padding: 20px; background: #f7f7f5; border-radius: 8px; text-align: center; font-size: 12px; color: #666; }
</style>
</head>
<body>
  <div class='header'>
    <div class='logo-name'><span>LA ROCA</span> COMERCIAL</div>
    <div style='font-size:13px;color:#666;margin-top:4px'>Barrio Arriba, Comayagua, Honduras · Tel: 2772-2660</div>
    <div class='folio'>Folio: ${folio} · ${fecha}</div>
  </div>
  <div class='title'>Comprobante Digital de Transacción</div>
  <div class='row'><span class='label'>Cliente:</span><span class='value'>${ct.nombre || 'N/A'}</span></div>
  <div class='row'><span class='label'>Teléfono:</span><span class='value'>${ct.telefono || 'N/A'}</span></div>
  <div class='row'><span class='label'>Producto:</span><span class='value'>${producto}</span></div>
  <div class='row'><span class='label'>Modalidad de pago:</span><span class='value'>${pago}</span></div>
  <div class='row'><span class='label'>Asesor:</span><span class='value'>${vd.nombre || 'N/A'}</span></div>
  <div class='row'><span class='label'>Sucursal:</span><span class='value'>${vd.sucursal || 'Comayagua'}</span></div>
  <div class='row'><span class='label'>Fecha de venta:</span><span class='value'>${fecha}</span></div>
  <div class='seal'>Este comprobante certifica la transacción realizada en La Roca Comercial.<br/>Conserve este documento para cualquier gestión de garantía.</div>
  <div class='footer'>La Roca Comercial © 2024 · Comayagua, Honduras · Distribuidores oficiales MOVESA y Olympia</div>
</body>
</html>`;

return [{
  json: {
    htmlContent,
    folio,
    fecha,
    contacto: ct,
    vendedor: vd,
    tarjeta_id: data.id
  }
}];

const folio = $('Generar HTML Contrato').item.json.folio;
const telefono = $('Generar HTML Contrato').item.json.contacto.telefono;
const nombre = $('Generar HTML Contrato').item.json.contacto.nombre;

const pdfUrl = `https://upaenjotkocmdvfuobii.supabase.co/storage/v1/object/public/contratos/contrato-${folio}.pdf`;

return [{
  json: { pdfUrl, folio, telefono, nombre }
}];

